INSERT INTO scenario_groups (id, slug, category) VALUES
  ('00000000-0000-0000-0000-000000000015', 'social-connection1', 'social')
INSERT INTO scenarios (id, group_id, language_id, title, description, level, type, icon, sort_order) VALUES
  (
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation) VALUES
  ('00000000-0000-0000-0006-000000000009', 'en', 1, 'user', 'Quite a queue today, isn''t it?', 'Hôm nay xếp hàng đông quá nhỉ?'),
  ('00000000-0000-0000-0006-000000000009', 'en', 2, 'partner', 'Isn''t it! I''ve been here for about twenty minutes already.', 'Đúng vậy! Tôi đã đứng đây khoảng 20 phút rồi.'),
  ('00000000-0000-0000-0006-000000000009', 'en', 3, 'user', 'Same here. Are you heading somewhere nice today?', 'Tôi cũng vậy. Bạn đang đi đâu vui vẻ hôm nay không?'),
  ('00000000-0000-0000-0006-000000000009', 'en', 4, 'partner', 'Just back from a trip to Kyoto. You?', 'Tôi vừa đi Kyoto về. Còn bạn?'),
  ('00000000-0000-0000-0006-000000000009', 'en', 5, 'user', 'Oh nice! I''ve always wanted to go there. How was it?', 'Thật tuyệt! Tôi luôn muốn đến đó. Chuyến đi thế nào?'),
  ('00000000-0000-0000-0006-000000000009', 'en', 6, 'partner', 'Really lovely. We went in autumn so the leaves were incredible.', 'Thật tuyệt vời. Chúng tôi đi vào mùa thu nên lá rất đẹp.'),
  ('00000000-0000-0000-0006-000000000009', 'en', 7, 'user', 'I heard autumn is the best time to visit. Did you have a favourite spot?', 'Tôi nghe mùa thu là thời điểm đẹp nhất để thăm. Bạn có điểm yêu thích không?'),
  ('00000000-0000-0000-0006-000000000009', 'en', 8, 'partner', 'Arashiyama — the bamboo grove. Have you been to Japan before?', 'Arashiyama — rừng tre. Bạn đã từng đến Nhật Bản chưa?'),
  ('00000000-0000-0000-0006-000000000009', 'en', 9, 'user', 'Not yet, but it''s at the top of my list. I''m actually learning Japanese at the moment.', 'Chưa, nhưng nó đứng đầu danh sách của tôi. Tôi đang học tiếng Nhật đấy.'),
  ('00000000-0000-0000-0006-000000000009', 'en', 10, 'partner', 'Oh, that''s great! You''ll have such an advantage when you visit.', 'Ồ tuyệt quá! Bạn sẽ có lợi thế lớn khi đến thăm.'),
  ('00000000-0000-0000-0006-000000000009', 'en', 11, 'user', 'I hope so! The queue seems to be moving now at least.', 'Tôi hy vọng vậy! Hàng có vẻ đang nhúc nhích rồi.'),
  ('00000000-0000-0000-0006-000000000009', 'en', 12, 'partner', 'Finally! Nice chatting with you. Hope your trip to Japan happens soon.', 'Cuối cùng rồi! Rất vui được trò chuyện. Chúc chuyến đi Nhật Bản của bạn sớm thành hiện thực.');
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation, furigana, romaji) VALUES
  ('00000000-0000-0000-0006-000000000010', 'ja', 1, 'user', '今日は並んでいますね。', 'Hôm nay xếp hàng đông nhỉ.', 'きょうはならんでいますね。', 'Kyō wa narande imasu ne.'),
  ('00000000-0000-0000-0006-000000000010', 'ja', 2, 'partner', 'そうですね！もう20分ほど待っています。', 'Đúng vậy! Tôi đã đứng chờ khoảng 20 phút rồi.', 'そうですね！もうにじゅっぷんほどまっています。', 'Sō desu ne! Mō nijuppun hodo matte imasu.'),
  ('00000000-0000-0000-0006-000000000010', 'ja', 3, 'user', '私もです。今日はどちらへ？', 'Tôi cũng vậy. Hôm nay bạn đi đâu vậy?', 'わたしもです。きょうはどちらへ？', 'Watashi mo desu. Kyō wa dochira e?'),
  ('00000000-0000-0000-0006-000000000010', 'ja', 4, 'partner', '京都に行ってきたんです。あなたは？', 'Tôi vừa đi Kyoto về. Còn bạn?', 'きょうとにいってきたんです。あなたは？', 'Kyōto ni itte kita n desu. Anata wa?'),
  ('00000000-0000-0000-0006-000000000010', 'ja', 5, 'user', 'いいですね！ずっと行ってみたいと思っていました。どうでしたか？', 'Thật tuyệt! Tôi luôn muốn đến đó. Chuyến đi thế nào?', 'いいですね！ずっといってみたいとおもっていました。どうでしたか？', 'Ii desu ne! Zutto itte mitai to omotte imashita. Dō deshita ka?'),
  ('00000000-0000-0000-0006-000000000010', 'ja', 6, 'partner', 'とても良かったです。秋に行ったので、紅葉がすごくきれいでした。', 'Rất tuyệt. Tôi đi vào mùa thu nên lá đỏ rất đẹp.', 'とてもよかったです。あきにいったので、こうようがすごくきれいでした。', 'Totemo yokatta desu. Aki ni itta node, kōyō ga sugoku kirei deshita.'),
  ('00000000-0000-0000-0006-000000000010', 'ja', 7, 'user', '秋が一番いい時期だと聞いています。お気に入りの場所はありましたか？', 'Tôi nghe mùa thu là thời điểm đẹp nhất. Bạn có điểm yêu thích không?', 'あきがいちばんいいじきだとさいてきだときいています。おきにいりのばしょはありましたか？', 'Aki ga ichiban ii jiki da to kiite imasu. O-ki ni iri no basho wa arimashita ka?'),
  ('00000000-0000-0000-0006-000000000010', 'ja', 8, 'partner', '嵐山の竹林がよかったですね。日本には行ったことがありますか？', 'Rừng tre Arashiyama rất đẹp. Bạn đã từng đến Nhật Bản chưa?', 'あらしやまのちくりんがよかったですね。にほんにはいったことがありますか？', 'Arashiyama no chikurin ga yokatta desu ne. Nihon ni wa itta koto ga arimasu ka?'),
  ('00000000-0000-0000-0006-000000000010', 'ja', 9, 'user', 'まだないんですが、ぜひ行ってみたいです。実は今、日本語を勉強しているんです。', 'Chưa, nhưng tôi rất muốn đến. Thực ra tôi đang học tiếng Nhật đấy.', 'まだないんですが、ぜひいってみたいです。じつはいま、にほんごをべんきょうしているんです。', 'Mada nai n desu ga, zehi itte mitai desu. Jitsu wa ima, Nihon-go wo benkyō shite iru n desu.'),
  ('00000000-0000-0000-0006-000000000010', 'ja', 10, 'partner', 'それは素晴らしい！行ったときにきっと役に立ちますよ。', 'Thật tuyệt vời! Khi bạn đến chắc chắn sẽ có ích lắm.', 'それはすばらしい！いったときにきっとやくにたちますよ。', 'Sore wa subarashii! Itta toki ni kitto yaku ni tachimasu yo.'),
  ('00000000-0000-0000-0006-000000000010', 'ja', 11, 'user', 'そうだといいですね！列がようやく動きだしてきましたよ。', 'Tôi hy vọng vậy! Hàng cuối cùng cũng bắt đầu di chuyển rồi.', 'そうだといいですね！れつがようやくうごきだしてきましたよ。', 'Sō da to ii desu ne! Retsu ga yōyaku ugokidashite kimashita yo.'),
  ('00000000-0000-0000-0006-000000000010', 'ja', 12, 'partner', 'やっとですね！お話しできてよかったです。早く日本に行けるといいですね。', 'Cuối cùng rồi! Rất vui được trò chuyện. Hy vọng bạn sớm đến được Nhật Bản.', 'やっとですね！おはなしできてよかったです。はやくにほんにいけるといいですね。', 'Yatto desu ne! O-hanashi dekite yokatta desu. Hayaku Nihon ni ikeru to ii desu ne.');
INSERT INTO scenario_groups (id, slug, category) VALUES
  ('00000000-0000-0000-0000-000000000016', 'social-connection2', 'social')
INSERT INTO scenarios (id, group_id, language_id, title, description, level, type, icon, sort_order) VALUES
  (
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation) VALUES
  ('00000000-0000-0000-0006-000000000011', 'en', 1, 'partner', 'I loved your presentation today. The slides were really clear.', 'Tôi thích bài thuyết trình của bạn hôm nay. Các slide rất rõ ràng.'),
  ('00000000-0000-0000-0006-000000000011', 'en', 2, 'user', 'Thank you so much — that means a lot. I spent a while thinking about how to structure it.', 'Cảm ơn bạn rất nhiều — điều đó có ý nghĩa lắm. Tôi đã dành thời gian suy nghĩ về cách sắp xếp.'),
  ('00000000-0000-0000-0006-000000000011', 'en', 3, 'partner', 'It really showed. The data visualisation especially was great.', 'Điều đó thể hiện rõ. Đặc biệt phần trực quan hoá dữ liệu rất hay.'),
  ('00000000-0000-0000-0006-000000000011', 'en', 4, 'user', 'I''m glad that landed well. By the way, I''ve been meaning to say — your feedback last week was really helpful.', 'Tôi vui vì điều đó hiệu quả. Nhân tiện, tôi muốn nói — phản hồi của bạn tuần trước rất hữu ích.'),
  ('00000000-0000-0000-0006-000000000011', 'en', 5, 'partner', 'Oh, was it? I just said what I thought.', 'Ồ vậy sao? Tôi chỉ nói những gì tôi nghĩ thôi.'),
  ('00000000-0000-0000-0006-000000000011', 'en', 6, 'user', 'Exactly — that''s what made it useful. Honest and specific feedback is rare.', 'Đúng vậy — đó là điều làm nó hữu ích. Phản hồi thành thật và cụ thể thật hiếm.'),
  ('00000000-0000-0000-0006-000000000011', 'en', 7, 'partner', 'Well, thank you for saying that. I appreciate it.', 'Vậy thì, cảm ơn bạn đã nói điều đó. Tôi trân trọng điều đó.'),
  ('00000000-0000-0000-0006-000000000011', 'en', 8, 'user', 'Also — love the new jacket, by the way. It suits you.', 'À — tôi cũng thích chiếc áo khoác mới của bạn. Nó hợp với bạn lắm.'),
  ('00000000-0000-0000-0006-000000000011', 'en', 9, 'partner', 'Oh, thanks! I wasn''t sure about it actually. Good to know.', 'Ồ cảm ơn! Thực ra tôi không chắc về nó. Tốt khi biết điều đó.'),
  ('00000000-0000-0000-0006-000000000011', 'en', 10, 'user', 'Definitely keep it. The colour works really well.', 'Nhất định giữ nó lại. Màu sắc rất hợp.'),
  ('00000000-0000-0000-0006-000000000011', 'en', 11, 'partner', 'You''re very good at noticing things! You''d be great as a stylist.', 'Bạn rất giỏi quan sát! Bạn sẽ làm nhà tạo mẫu giỏi đấy.'),
  ('00000000-0000-0000-0006-000000000011', 'en', 12, 'user', 'Ha! Maybe a side career. Thanks — you''ve made my day.', 'Ha! Có thể là nghề tay trái. Cảm ơn — bạn đã làm tôi vui cả ngày rồi.');
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation, furigana, romaji) VALUES
  ('00000000-0000-0000-0006-000000000012', 'ja', 1, 'partner', '今日のプレゼン、よかったですよ。スライドがとてもわかりやすかった。', 'Bài thuyết trình hôm nay của bạn rất hay. Slide rất dễ hiểu.', 'きょうのプレゼン、よかったですよ。スライドがとてもわかりやすかった。', 'Kyō no purezen, yokatta desu yo. Suraido ga totemo wakariyasukatta.'),
  ('00000000-0000-0000-0006-000000000012', 'ja', 2, 'user', 'ありがとうございます。そう言っていただけると嬉しいです。構成をどうするか、少し時間をかけて考えたんです。', 'Cảm ơn bạn. Thật vui khi nghe điều đó. Tôi đã mất khá nhiều thời gian suy nghĩ về cách sắp xếp.', 'ありがとうございます。そういっていただけるとうれしいです。こうせいをどうするか、すこしじかんをかけてかんがえたんです。', 'Arigatō gozaimasu. Sō itte itadakeru to ureshii desu. Kōsei wo dō suru ka, sukoshi jikan wo kakete kangaeta n desu.'),
  ('00000000-0000-0000-0006-000000000012', 'ja', 3, 'partner', 'それが伝わりました。特にデータの見せ方がよかったです。', 'Điều đó thể hiện rõ. Đặc biệt cách trình bày dữ liệu rất hay.', 'それがつたわりました。とくにデータのみせかたがよかったです。', 'Sore ga tsutawarimashita. Toku ni dēta no mise-kata ga yokatta desu.'),
  ('00000000-0000-0000-0006-000000000012', 'ja', 4, 'user', 'よかったです。ところで、先週のフィードバックがとても参考になりました。', 'Mừng quá. Nhân tiện, phản hồi của bạn tuần trước rất có ích.', 'よかったです。ところで、せんしゅうのフィードバックがとてもさんこうになりました。', 'Yokatta desu. Tokoro de, senshū no fīdobakku ga totemo sankō ni narimashita.'),
  ('00000000-0000-0000-0006-000000000012', 'ja', 5, 'partner', 'そうですか？思ったことを言っただけですよ。', 'Vậy à? Tôi chỉ nói những gì mình nghĩ thôi.', 'そうですか？おもったことをいっただけですよ。', 'Sō desu ka? Omotta koto wo itta dake desu yo.'),
  ('00000000-0000-0000-0006-000000000012', 'ja', 6, 'user', 'それがよかったんです。率直で具体的なフィードバックは、なかなか得られないですから。', 'Đó chính là điều làm nó hữu ích. Phản hồi thẳng thắn và cụ thể thật hiếm có.', 'それがよかったんです。そっちょくでぐたいてきなフィードバックは、なかなかえられないですから。', 'Sore ga yokatta n desu. Sōchoku de gutaiteki na fīdobakku wa, nakanaka erarenai desu kara.'),
  ('00000000-0000-0000-0006-000000000012', 'ja', 7, 'partner', 'そう言ってもらえると嬉しいです。ありがとう。', 'Thật vui khi nghe điều đó. Cảm ơn bạn.', 'そういってもらえるとうれしいです。ありがとう。', 'Sō itte moraeru to ureshii desu. Arigatō.'),
  ('00000000-0000-0000-0006-000000000012', 'ja', 8, 'user', 'それと、新しいジャケット、似合っていますよ。', 'À, áo khoác mới của bạn hợp lắm đó.', 'それと、あたらしいジャケット、にあっていますよ。', 'Sore to, atarashii jaketto, niatte imasu yo.'),
  ('00000000-0000-0000-0006-000000000012', 'ja', 9, 'partner', 'えっ、ありがとう！実はどうかなと思ってたんですよ。よかった。', 'Ồ cảm ơn! Thực ra tôi cũng không chắc. Mừng quá.', 'えっ、ありがとう！じつはどうかなとおもってたんですよ。よかった。', 'E, arigatō! Jitsu wa dō ka na to omotte ta n desu yo. Yokatta.'),
  ('00000000-0000-0000-0006-000000000012', 'ja', 10, 'user', 'ぜひ着続けてください。色がとても合っていると思います。', 'Nhất định tiếp tục mặc nó nhé. Tôi nghĩ màu sắc rất hợp với bạn.', 'ぜひきつづけてください。いろがとてもあっていると思います。', 'Zehi ki-tsuzukete kudasai. Iro ga totemo atte iru to omoimasu.'),
  ('00000000-0000-0000-0006-000000000012', 'ja', 11, 'partner', '気づくのが上手いですね！スタイリストに向いてますよ。', 'Bạn rất tinh ý! Bạn hợp làm nhà tạo mẫu đó.', 'きづくのがうまいですね！スタイリストにむいてますよ。', 'Kizuku no ga umai desu ne! Sutairisuto ni muite masu yo.'),
  ('00000000-0000-0000-0006-000000000012', 'ja', 12, 'user', 'ありがとう！副業にしようかな。おかげで今日は気分がいいです。', 'Cảm ơn! Có lẽ làm nghề tay trái vậy. Nhờ bạn hôm nay tôi vui cả ngày rồi.', 'ありがとう！ふくぎょうにしようかな。おかげできょうはきぶんがいいです。', 'Arigatō! Fukugyō ni shiyō ka na. Okage de kyō wa kibun ga ii desu.');
INSERT INTO scenario_groups (id, slug, category) VALUES
  ('00000000-0000-0000-0000-000000000017', 'social-connection3', 'social')
INSERT INTO scenarios (id, group_id, language_id, title, description, level, type, icon, sort_order) VALUES
  (
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation) VALUES
  ('00000000-0000-0000-0006-000000000013', 'en', 1, 'user', 'Hey, a few of us are grabbing dinner on Friday — would you like to join?', 'Này, một vài người trong chúng tôi sẽ đi ăn tối thứ Sáu — bạn có muốn cùng không?'),
  ('00000000-0000-0000-0006-000000000013', 'en', 2, 'partner', 'That sounds great! Where are you thinking?', 'Nghe hay đó! Bạn đang nghĩ đến đâu vậy?'),
  ('00000000-0000-0000-0006-000000000013', 'en', 3, 'user', 'We''re thinking of that new ramen place on the high street. Around seven.', 'Chúng tôi đang nghĩ đến tiệm ramen mới trên phố chính. Khoảng bảy giờ.'),
  ('00000000-0000-0000-0006-000000000013', 'en', 4, 'partner', 'Oh, I''ve been wanting to try that! Count me in.', 'Ồ, tôi đã muốn thử chỗ đó! Tính tôi vào nhé.'),
  ('00000000-0000-0000-0006-000000000013', 'en', 5, 'user', 'Great. I''ll let the group know. Oh — by the way, are you free Sunday afternoon?', 'Tuyệt. Tôi sẽ báo nhóm biết. À — nhân tiện, bạn có rảnh chiều Chủ nhật không?'),
  ('00000000-0000-0000-0006-000000000013', 'en', 6, 'partner', 'Sunday? I''m afraid I can''t — I''ve got a family thing.', 'Chủ nhật? Tôi e là không được — tôi có việc gia đình.'),
  ('00000000-0000-0000-0006-000000000013', 'en', 7, 'user', 'No worries at all. What about the following weekend?', 'Không sao cả. Vậy cuối tuần sau thì sao?'),
  ('00000000-0000-0000-0006-000000000013', 'en', 8, 'partner', 'The following Saturday should work for me. What did you have in mind?', 'Thứ Bảy sau tôi có thể. Bạn đang nghĩ đến gì vậy?'),
  ('00000000-0000-0000-0006-000000000013', 'en', 9, 'user', 'There''s a food market in the park — thought it might be fun to check out.', 'Có chợ ẩm thực trong công viên — tôi nghĩ có thể vui để ghé thăm.'),
  ('00000000-0000-0000-0006-000000000013', 'en', 10, 'partner', 'Oh that sounds lovely. Let''s do it.', 'Ồ nghe thật tuyệt. Hãy làm vậy đi.'),
  ('00000000-0000-0000-0006-000000000013', 'en', 11, 'user', 'Brilliant. Say, eleven? We can grab brunch there too.', 'Tuyệt. Khoảng mười một giờ nhé? Chúng ta có thể ăn brunch ở đó luôn.'),
  ('00000000-0000-0000-0006-000000000013', 'en', 12, 'partner', 'Perfect. I''ll put it in my calendar now so I don''t forget.', 'Hoàn hảo. Tôi sẽ ghi vào lịch ngay để không quên.');
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation, furigana, romaji) VALUES
  ('00000000-0000-0000-0006-000000000014', 'ja', 1, 'user', '金曜日に何人かで夕食に行くんですけど、一緒に来ませんか？', 'Thứ Sáu một vài người trong chúng tôi sẽ đi ăn tối, bạn có muốn cùng không?', 'きんようびになんにんかでゆうしょくにいくんですけど、いっしょにきませんか？', 'Kin''yōbi ni nan-nin ka de yūshoku ni iku n desu kedo, issho ni kimasen ka?'),
  ('00000000-0000-0000-0006-000000000014', 'ja', 2, 'partner', 'いいですね！どこを考えていますか？', 'Nghe hay đó! Bạn đang nghĩ đến đâu vậy?', 'いいですね！どこをかんがえていますか？', 'Ii desu ne! Doko wo kangaete imasu ka?'),
  ('00000000-0000-0000-0006-000000000014', 'ja', 3, 'user', '大通りの新しいラーメン屋さんを考えています。7時ごろです。', 'Chúng tôi đang nghĩ đến tiệm ramen mới trên phố chính. Khoảng bảy giờ.', 'おおどおりのあたらしいラーメンやさんをかんがえています。しちじごろです。', 'Ōdōri no atarashii rāmen-ya-san wo kangaete imasu. Shichi-ji goro desu.'),
  ('00000000-0000-0000-0006-000000000014', 'ja', 4, 'partner', '行ってみたかったお店です！ぜひ参加します。', 'Tiệm tôi đã muốn thử! Tôi sẽ tham gia.', 'いってみたかったおみせです！ぜひさんかします。', 'Itte mitakatta o-mise desu! Zehi sanka shimasu.'),
  ('00000000-0000-0000-0006-000000000014', 'ja', 5, 'user', 'よかった。グループに伝えますね。ところで、日曜日の午後は空いていますか？', 'Tốt quá. Tôi sẽ báo nhóm. Nhân tiện, chiều Chủ nhật bạn có rảnh không?', 'よかった。グループにつたえますね。ところで、にちようびのごごはあいていますか？', 'Yokatta. Gurūpu ni tsutaemasu ne. Tokoro de, Nichiyōbi no gogo wa aite imasu ka?'),
  ('00000000-0000-0000-0006-000000000014', 'ja', 6, 'partner', '日曜日ですか。申し訳ないんですが、家族の用事があって…。', 'Chủ nhật à. Thật xin lỗi nhưng tôi có việc gia đình...', 'にちようびですか。もうしわけないんですが、かぞくのようじがあって…。', 'Nichiyōbi desu ka. Mōshiwake nai n desu ga, kazoku no yōji ga atte...'),
  ('00000000-0000-0000-0006-000000000014', 'ja', 7, 'user', '大丈夫ですよ。その次の週末はどうですか？', 'Không sao đâu. Vậy cuối tuần sau thì sao?', 'だいじょうぶですよ。そのつぎのしゅうまつはどうですか？', 'Daijōbu desu yo. Sono tsugi no shūmatsu wa dō desu ka?'),
  ('00000000-0000-0000-0006-000000000014', 'ja', 8, 'partner', '次の土曜日なら大丈夫そうです。何を考えていましたか？', 'Thứ Bảy sau có vẻ được. Bạn đang nghĩ gì vậy?', 'つぎのどようびならだいじょうぶそうです。なにをかんがえていましたか？', 'Tsugi no Doyōbi nara daijōbu sō desu. Nani wo kangaete imashita ka?'),
  ('00000000-0000-0000-0006-000000000014', 'ja', 9, 'user', '公園でフードマーケットがあるんですよ。面白そうかと思って。', 'Có chợ ẩm thực trong công viên đó. Tôi nghĩ có vẻ thú vị.', 'こうえんでフードマーケットがあるんですよ。おもしろそうかとおもって。', 'Kōen de fūdo mākketto ga aru n desu yo. Omoshiro-sō ka to omotte.'),
  ('00000000-0000-0000-0006-000000000014', 'ja', 10, 'partner', 'それは楽しそうですね。ぜひ行きましょう。', 'Nghe vui đó. Hãy đi thôi.', 'それはたのしそうですね。ぜひいきましょう。', 'Sore wa tanoshisō desu ne. Zehi ikimashō.'),
  ('00000000-0000-0000-0006-000000000014', 'ja', 11, 'user', 'よかった！11時ごろはどうですか？ブランチも食べられますよ。', 'Tốt quá! Khoảng 11 giờ thế nào? Chúng ta có thể ăn brunch ở đó luôn.', 'よかった！じゅういちじごろはどうですか？ブランチもたべられますよ。', 'Yokatta! Jū-ichi-ji goro wa dō desu ka? Buranchi mo taberaremasu yo.'),
  ('00000000-0000-0000-0006-000000000014', 'ja', 12, 'partner', 'いいですね。忘れないよう今すぐカレンダーに入れます。', 'Tuyệt. Tôi sẽ ghi vào lịch ngay để không quên.', 'いいですね。わすれないようにいますぐカレンダーにいれます。', 'Ii desu ne. Wasurenai yō ni imasugu karendā ni iremasu.');
INSERT INTO scenario_groups (id, slug, category) VALUES
  ('00000000-0000-0000-0000-000000000018', 'social-connection4', 'social')
INSERT INTO scenarios (id, group_id, language_id, title, description, level, type, icon, sort_order) VALUES
  (
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation) VALUES
  ('00000000-0000-0000-0006-000000000015', 'en', 1, 'partner', 'Excuse me, do you mind if I sit here? All the other benches are taken.', 'Xin lỗi, tôi ngồi đây được không? Tất cả ghế khác đều có người.'),
  ('00000000-0000-0000-0006-000000000015', 'en', 2, 'user', 'Please, go ahead. It''s a lovely day to be out, isn''t it?', 'Xin mời. Hôm nay thời tiết đẹp để ra ngoài nhỉ?'),
  ('00000000-0000-0000-0006-000000000015', 'en', 3, 'partner', 'It really is. I try to walk here every morning if the weather allows.', 'Đúng vậy. Tôi cố gắng đi bộ ở đây mỗi sáng nếu thời tiết cho phép.'),
  ('00000000-0000-0000-0006-000000000015', 'en', 4, 'user', 'That''s a wonderful habit. Have you lived in this area for long?', 'Đó là thói quen tuyệt vời. Bạn đã sống ở khu vực này lâu chưa?'),
  ('00000000-0000-0000-0006-000000000015', 'en', 5, 'partner', 'Over forty years now. This park has changed so much. It used to be much smaller.', 'Hơn 40 năm rồi. Công viên này đã thay đổi rất nhiều. Trước đây nhỏ hơn nhiều.'),
  ('00000000-0000-0000-0006-000000000015', 'en', 6, 'user', 'Really? I''d love to hear what it was like. Do you remember when they expanded it?', 'Thật à? Tôi muốn nghe về nó trước đây. Bạn có nhớ khi họ mở rộng không?'),
  ('00000000-0000-0000-0006-000000000015', 'en', 7, 'partner', 'I do. They added the pond in the eighties. Before that it was just open grass.', 'Nhớ chứ. Họ thêm cái ao vào những năm 80. Trước đó chỉ là bãi cỏ trống.'),
  ('00000000-0000-0000-0006-000000000015', 'en', 8, 'user', 'The pond is my favourite part! What do you think has changed for the better?', 'Cái ao là phần tôi thích nhất! Bạn nghĩ điều gì đã thay đổi tốt hơn?'),
  ('00000000-0000-0000-0006-000000000015', 'en', 9, 'partner', 'More green spaces, more paths. It''s much more walkable now.', 'Nhiều không gian xanh hơn, nhiều đường đi hơn. Giờ đi bộ thoải mái hơn nhiều.'),
  ('00000000-0000-0000-0006-000000000015', 'en', 10, 'user', 'I completely agree. It must be nice to have watched it grow over the years.', 'Tôi hoàn toàn đồng ý. Chắc thật thú vị khi được chứng kiến nó phát triển theo năm tháng.'),
  ('00000000-0000-0000-0006-000000000015', 'en', 11, 'partner', 'It is. You young people are lucky to have it this nice.', 'Đúng vậy. Các bạn trẻ may mắn có được công viên đẹp như vậy.'),
  ('00000000-0000-0000-0006-000000000015', 'en', 12, 'user', 'Thanks to people like you who''ve looked after it over the years. Enjoy your morning walk.', 'Nhờ những người như bạn đã chăm sóc nó qua nhiều năm. Chúc bạn đi bộ buổi sáng vui nhé.');
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation, furigana, romaji) VALUES
  ('00000000-0000-0000-0006-000000000016', 'ja', 1, 'partner', 'すみません、ここに座ってもよいですか？他のベンチが全部ふさがっていて。', 'Xin lỗi, tôi ngồi đây được không? Tất cả ghế khác đều có người.', 'すみません、ここにすわってもよいですか？ほかのベンチがぜんぶふさがっていて。', 'Sumimasen, koko ni suwatte mo yoi desu ka? Hoka no benchi ga zenbu fusagatte ite.'),
  ('00000000-0000-0000-0006-000000000016', 'ja', 2, 'user', 'どうぞ、お座りください。今日はお天気がよくて、気持ちいいですね。', 'Xin mời ngồi. Hôm nay trời đẹp, dễ chịu nhỉ.', 'どうぞ、おすわりください。きょうはおてんきがよくて、きもちいいですね。', 'Dōzo, o-suwari kudasai. Kyō wa o-tenki ga yokute, kimochi ii desu ne.'),
  ('00000000-0000-0000-0006-000000000016', 'ja', 3, 'partner', 'そうですね。お天気がよければ、毎朝ここを歩くようにしているんですよ。', 'Đúng vậy. Nếu trời đẹp, tôi cố gắng đi bộ ở đây mỗi sáng.', 'そうですね。おてんきがよければ、まいあさここをあるくようにしているんですよ。', 'Sō desu ne. O-tenki ga yokereba, mai-asa koko wo aruku yō ni shite iru n desu yo.'),
  ('00000000-0000-0000-0006-000000000016', 'ja', 4, 'user', '素晴らしい習慣ですね。この辺りには長くお住まいなのですか？', 'Thói quen tuyệt vời. Bạn đã sống ở khu vực này lâu chưa?', 'すばらしいしゅうかんですね。このあたりにはながくおすまいなのですか？', 'Subarashii shūkan desu ne. Kono atari ni wa nagaku o-sumai na no desu ka?'),
  ('00000000-0000-0000-0006-000000000016', 'ja', 5, 'partner', 'もう40年以上になります。この公園も随分変わりましたよ。昔はもっと小さかったんです。', 'Hơn 40 năm rồi. Công viên này cũng đã thay đổi nhiều lắm. Ngày xưa nhỏ hơn nhiều.', 'もうよんじゅうねんいじょうになります。このこうえんもずいぶんかわりましたよ。むかしはもっとちいさかったんです。', 'Mō yonjūnen ijō ni narimasu. Kono kōen mo zuibun kawarimashita yo. Mukashi wa motto chiisakatta n desu.'),
  ('00000000-0000-0000-0006-000000000016', 'ja', 6, 'user', 'そうなんですか！昔のお話を聞かせていただけますか？池ができたのはいつ頃ですか？', 'Thật à! Bạn có thể kể chuyện ngày xưa không? Cái ao được xây dựng khi nào?', 'そうなんですか！むかしのおはなしをきかせていただけますか？いけができたのはいつごろですか？', 'Sō nan desu ka! Mukashi no o-hanashi wo kikasete itadakemasu ka? Ike ga dekita no wa itsu goro desu ka?'),
  ('00000000-0000-0000-0006-000000000016', 'ja', 7, 'partner', '池は昭和の終わり頃にできたんですよ。それまでは広い草地だったんです。', 'Cái ao được làm vào cuối thời Shōwa. Trước đó chỉ là bãi cỏ rộng.', 'いけはしょうわのおわりごろにできたんですよ。それまではひろいくさちだったんです。', 'Ike wa Shōwa no owari goro ni dekita n desu yo. Sore made wa hiroi kusachi datta n desu.'),
  ('00000000-0000-0000-0006-000000000016', 'ja', 8, 'user', '池が一番好きな場所です！変わってよかったと思うところはどこですか？', 'Cái ao là nơi tôi thích nhất! Bạn nghĩ điều gì thay đổi là tốt nhất?', 'いけがいちばんすきなばしょです！かわってよかったとおもうところはどこですか？', 'Ike ga ichiban suki na basho desu! Kawatte yokatta to omou tokoro wa doko desu ka?'),
  ('00000000-0000-0000-0006-000000000016', 'ja', 9, 'partner', '緑が増えて、散歩道もたくさんできました。今の方がずっと歩きやすいですね。', 'Xanh hơn và nhiều đường đi hơn. Bây giờ đi bộ thoải mái hơn nhiều.', 'みどりがふえて、さんぽみちもたくさんできました。いまのほうがずっとあるきやすいですね。', 'Midori ga fuete, sanpomichi mo takusan dekimashita. Ima no hō ga zutto arukiyasui desu ne.'),
  ('00000000-0000-0000-0006-000000000016', 'ja', 10, 'user', '本当にそうですね。長年ここの変化を見守ってこられたのは、素敵なことだと思います。', 'Thật vậy. Tôi nghĩ thật tuyệt khi được chứng kiến sự thay đổi nơi này qua nhiều năm.', 'ほんとうにそうですね。ながねんここのへんかをみまもってこられたのは、すてきなことだとおもいます。', 'Hontō ni sō desu ne. Nagannen koko no henka wo mimamotte korareta no wa, suteki na koto da to omoimasu.'),
  ('00000000-0000-0000-0006-000000000016', 'ja', 11, 'partner', 'ありがとう。あなたたち若い人がこんなに良い公園を使えるのは、うれしいですよ。', 'Cảm ơn. Thật vui khi các bạn trẻ có thể tận hưởng công viên đẹp như vậy.', 'ありがとう。あなたたちわかいひとがこんなによいこうえんをつかえるのは、うれしいですよ。', 'Arigatō. Anata-tachi wakai hito ga konna ni yoi kōen wo tsukaeru no wa, ureshii desu yo.'),
  ('00000000-0000-0000-0006-000000000016', 'ja', 12, 'user', '長年大切にしてくださった皆さんのおかげです。どうぞ、朝の散歩をお楽しみください。', 'Đó là nhờ những người như bạn đã gìn giữ nó bao năm nay. Chúc bạn thưởng thức buổi đi bộ sáng.', 'ながねんたいせつにしてくださったみなさんのおかげです。どうぞ、あさのさんぽをおたのしみください。', 'Nagannen taisetsu ni shite kudasatta mina-san no okage desu. Dōzo, asa no sanpo wo o-tanoshimi kudasai.');
